<template>
  <div class="flex-direction-column">
    <div
      class="g-page-container-with-header"
      v-for="(config, index) in configDataList"
      :key="index"
    >
      <div class="container-header flex-space-between">
        <span class="title config">配置 {{ config.devName }}</span>
        <span class="title file-path">文件位置：{{ config.configFile }}</span>
        <div class="g-button save-all-btn" @click="handleRefreshBatch(config)">
          全部保存
        </div>
      </div>

      <div class="container-content">
        <div
          class="g-kv-pair"
          v-for="(param, pIndex) in config.paramDataList"
          :key="pIndex"
        >
          <div class="value">{{ param.txt }}</div>
          <div class="value">{{ param.val }}</div>
          <div class="value">
            <!-- 如果 values 有内容则渲染为下拉框 -->
            <select
              v-if="param.values"
              v-model="param.editValue"
              class="editable-input"
            >
              <option
                v-for="option in param.values.split(',')"
                :key="option"
                :value="option"
              >
                {{ option }}
              </option>
            </select>
            <!-- 否则仍是输入框 -->
            <input
              v-else
              v-model="param.editValue"
              class="editable-input"
              type="text"
            />
          </div>
          <div class="g-button" @click="handleRefreshRow(param, config)">
            保存
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup>
import { computed } from 'vue'
import { storeToRefs } from 'pinia'
import { useWslStore } from '@/store/modules/ws.js'
import { useCommand } from '@/hooks/useCommand.js'
import { ElMessage } from 'element-plus'
import { useConfigMerge } from '@/hooks/useConfigMerge'

const store = useWslStore()
const { received } = storeToRefs(store)
const { sendConfigData } = useCommand(store)

// 获取配置数据configDataList
const { configDataList } = useConfigMerge(
  computed(() => received.value?.statusData?.configDataList)
)

// 单行保存
const handleRefreshRow = (param, config) => {
  const newVal = param.editValue?.trim()

  if (!newVal) {
    ElMessage.error(`参数 ${param.key} 的值不能为空`)
    return
  }

  // 根据 param.type 判断是否校验为数字
  if (param.type === 'number' && isNaN(Number(newVal))) {
    ElMessage.error(`参数 ${param.key} 必须为数字`)
    return
  }

  if (param.val !== newVal) {
    sendConfigData(config.devName, config.configFile, [
      { key: param.key, val: newVal }
    ])
    ElMessage.success(`已保存参数 ${param.key} = ${newVal}`)
  } else {
    ElMessage.warning('该参数未发生变更，无需保存')
  }
}

// 批量保存
const handleRefreshBatch = (config) => {
  const emptyParams = []
  const nonNumberParams = []

  config.paramDataList.forEach((p) => {
    const val = p.editValue?.trim()
    if (!val) {
      emptyParams.push(p.key)
    } else if (p.type === 'number' && isNaN(Number(val))) {
      nonNumberParams.push(p.key)
    }
  })

  if (emptyParams.length > 0) {
    ElMessage.error(
      `请填写 ${config.devName} 的参数：${emptyParams.join('、')}`
    )
    return
  }

  if (nonNumberParams.length > 0) {
    ElMessage.error(
      `参数 ${config.devName} 中以下项必须为数字：${nonNumberParams.join('、')}`
    )
    return
  }

  const changedParams = config.paramDataList
    .filter((p) => p.val !== p.editValue?.trim())
    .map((p) => ({ key: p.key, val: p.editValue.trim() }))

  if (changedParams.length > 0) {
    sendConfigData(config.devName, config.configFile, changedParams)
    ElMessage.success(
      `已批量保存 ${config.devName} 的 ${changedParams.length} 个修改项`
    )
  } else {
    ElMessage.warning('该配置未发生变更，无需全部保存')
  }
}
</script>

<style lang="less" scoped>
.save-all-btn {
  background-color: #90c2ff;
  color: #fff;
}

.container-header {
  .config {
    width: 29%;
  }
  .file-path {
    width: 60%;
  }
}
</style>
