//专用于config（特定数据结构，有editValue）合并更新单行or勾选行数据与未更新的数据行

import { ref, watch, computed } from 'vue'

export function useConfigMerge(rawListRef) {
  const lastList = ref([])

  watch(
    rawListRef,
    (newList) => {
      if (!newList || newList.length === 0) {
        lastList.value = [
          {
            devName: '暂无',
            configFile: '暂无',
            paramDataList: [
              {
                key: 'empty1',
                txt: '暂无参数',
                val: '暂无数据',
                editValue: '',
                values: '1,2'
              },
              {
                key: 'empty2',
                txt: '暂无参数',
                val: '暂无数据',
                editValue: ''
              }
            ]
          }
        ]
        return
      }

      const oldList = lastList.value

      // 深层 merge，保住 editValue
      const mergedList = newList.map((newItem) => {
        const oldItem = oldList.find(
          (o) =>
            o.devName === newItem.devName && o.configFile === newItem.configFile
        )

        const newParams = newItem.paramDataList || []
        const oldParams = oldItem?.paramDataList || []

        const mergedParams = newParams.map((newParam) => {
          const oldParam = oldParams.find((p) => p.key === newParam.key)
          return {
            ...newParam,
            editValue:
              oldParam?.editValue !== undefined
                ? oldParam.editValue
                : newParam.val ?? ''
          }
        })

        return {
          ...newItem,
          paramDataList: mergedParams
        }
      })

      lastList.value = mergedList
    },
    { immediate: true }
  )

  return {
    configDataList: computed(() => lastList.value)
  }
}
